const sqlite3 = require('sqlite3').verbose();
const { promisify } = require('util');

const db = new sqlite3.Database('./tasks.db');

// Promisify db methods
const dbRun = promisify(db.run.bind(db));
const dbAll = promisify(db.all.bind(db));
const dbGet = promisify(db.get.bind(db));

async function init() {
  await dbRun(`CREATE TABLE IF NOT EXISTS tasks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    title TEXT NOT NULL,
    completed INTEGER DEFAULT 0
  )`);
}

async function addTask(title) {
  const result = await dbRun('INSERT INTO tasks (title) VALUES (?)', title);
  console.log(`Task added with ID: ${result.lastID}`);
}

async function listTasks() {
  const rows = await dbAll('SELECT * FROM tasks');
  console.log('Tasks:');
  rows.forEach(row => {
    console.log(`${row.id}: [${row.completed ? 'x' : ' '}] ${row.title}`);
  });
}

async function completeTask(id) {
  await dbRun('UPDATE tasks SET completed = 1 WHERE id = ?', id);
  console.log(`Task ${id} marked completed.`);
}

async function deleteTask(id) {
  await dbRun('DELETE FROM tasks WHERE id = ?', id);
  console.log(`Task ${id} deleted.`);
}

// CLI parsing
(async () => {
  await init();
  const args = process.argv.slice(2);
  const command = args[0];

  switch (command) {
    case 'add':
      await addTask(args[1]);
      break;
    case 'list':
      await listTasks();
      break;
    case 'complete':
      await completeTask(args[1]);
      break;
    case 'delete':
      await deleteTask(args[1]);
      break;
    default:
      console.log('Commands: add <title>, list, complete <id>, delete <id>');
  }
  db.close();
})();
